4.5 How do I find fields that are numeric?

# using the following code!

nms &lt;- PISA_2018_school %&gt;% select(where(is.numeric)) %&gt;% names()
lbls &lt;- map_dfr(nms,\(nme){
  message(nme)
  lbl &lt;- attr(PISA_2018_school[[nme]], "label")
  row &lt;- c(nme, lbl)
  names(row) &lt;- c("name", "label")
  return(row)
})
